        {
            int rating;
            for(int i=0;i<a.Length;i++)
            {
                if(a[i].brand.Equals(targetBrand))
                {
                    rating = (a[i].noOfTestsPassed / a[i].noOfTestsConducted);
                    if(rating >=80)
                    {
                        a[i].setGrade("A1");
                    }
                    else
                    {
                        a[i].setGrade("B2");
                    }
                    return a[i];
                }
            }
            return null;
        }
    }

