            }
            else
            {
                Console.WriteLine("No Product Found");
            }

            double avg = calculateAveragePrice(products);
            Console.WriteLine(avg);
        }

        public static Product findProductWithHighestPrice(Product[] products, string category)
        {
            Product max = null;
            foreach (Product p in products)
            {
                if (p.category.Equals(category, StringComparison.OrdinalIgnoreCase))
                {
                    if (max == null || p.price > max.price)
                    {
                        max = p;
                    }
                }
            }
            return max;
        }

        public static double calculateAveragePrice(Product[] products)
        {
            if (products.Length == 0) return 0.0;
            double sum = 0;
            foreach (Product p in products)
            {
                sum += p.price;
            }
            return sum / products.Length;
        }
    }

