            Student max = findStudentWithMaxMarks(students);
            if (max != null)
            {
                Console.WriteLine(max.name + "::" + max.marks);
            }

            Student[] graded = getStudentsByGrade(students, searchGrade);
            foreach (Student s in graded)
            {
                Console.WriteLine(s.rollNo);
            }
        }

        public static Student findStudentWithMaxMarks(Student[] students)
        {
            if (students.Length == 0) return null;
            Student max = students[0];
            foreach (Student s in students)
            {
                if (s.marks > max.marks) max = s;
            }
            return max;
        }

        public static Student[] getStudentsByGrade(Student[] students, char grade)
        {
            List<Student> list = new List<Student>();
            foreach (Student s in students)
            {
                if (char.ToUpper(s.grade) == char.ToUpper(grade))
                {
                    list.Add(s);
                }
            }
            return list.ToArray();
        }
    }

    class Student
    {
        public int rollNo;
        public string name;
        public double marks;
        public char grade;

        public Student(int roll, string name, double marks, char grade)
        {
            this.rollNo = roll;
            this.name = name;
            this.marks = marks;
            this.grade = grade;
        }
    }
